const r={es:{Industrial:"Industrial",Arquitectónico:"Arquitectónico",Medioambiental:"Medioambiental"},en:{Industrial:"Industrial",Arquitectónico:"Architectural",Medioambiental:"Environmental"}},d={en:{"Control de vibraciones":"Vibration control","Aislamiento acústico":"Sound insulation","Acondicionamiento acústico":"Acoustic conditioning","Monitorización y diagnóstico":"Monitoring & diagnosis","Simulación y diseño FEM":"FEM simulation & design","Control acústico integral":"Integral acoustic control"}};function p(e,a){return a==="en"?{title:e.titleEn||e.title,tagline:e.taglineEn||e.tagline,solutionType:d.en[e.solutionType]||e.solutionTypeEn||e.solutionType,sector:r.en[e.sector]||e.sector,location:e.locationEn||e.location,keyFigure:e.keyFigureEn||e.keyFigure,regulation:e.regulationEn||e.regulation,technology:e.technologyEn||e.technology,challenge:e.challengeEn||e.challenge,solution:e.solutionEn||e.solution,result:e.resultEn||e.result}:{title:e.title,tagline:e.tagline,solutionType:e.solutionType,sector:r.es[e.sector]||e.sector,location:e.location,keyFigure:e.keyFigure,regulation:e.regulation,technology:e.technology,challenge:e.challenge,solution:e.solution,result:e.result}}const u={"complejo-hidroelectrico-alto-tamega":"/images/proyectos/complejo-hidroelectrico-alto-tamega.jpg","central-termica-castejon":"/images/proyectos/central-termica-castejon.jpg","monitorizacion-acustica-central-industrial":"/images/proyectos/monitorizacion-acustica-central-industrial.jpg","cabinas-acusticas-fabrica-vidrio":"/images/proyectos/cabinas-acusticas-fabrica-vidrio.jpg","cubierta-edificio-exclusivo-madrid":"/images/proyectos/cubierta-edificio-exclusivo-madrid.jpg","conservatorio-musica-edificio-historico":"/images/proyectos/conservatorio-musica-edificio-historico.jpg","silenciador-fem-soplantes-depuradora":"/images/proyectos/silenciador-fem-soplantes-depuradora.jpg","ruido-estructural-data-center-comsol":"/images/proyectos/ruido-estructural-data-center-comsol.jpg","sala-calderas-colindante-dormitorio":"/images/proyectos/sala-calderas-colindante-dormitorio.jpg","elevador-coches-entorno-residencial":"/images/proyectos/elevador-coches-entorno-residencial.jpg","local-emblematico-asturias":"/images/proyectos/local-emblematico-asturias.jpg","edificios-residenciales-vibraciones-ferrocarril":"/images/proyectos/edificios-residenciales-vibraciones-ferrocarril.jpg","platos-television-parlamento-europeo":"/images/proyectos/platos-television-parlamento-europeo.jpg","fabricas-incumplimientos-acusticos":"/images/proyectos/fabricas-incumplimientos-acusticos.jpg","chimeneas-hosteleria-centro-comercial":"/images/proyectos/chimeneas-hosteleria-centro-comercial.jpg","campo-eolico-mantenimiento-predictivo":"/images/proyectos/campo-eolico-mantenimiento-predictivo.jpg","mapa-acustico-3d-planta-industrial":"/images/proyectos/mapa-acustico-3d-planta-industrial.jpg","medicion-ruido-larga-distancia":"/images/proyectos/medicion-ruido-larga-distancia.jpg","data-center-centro-madrid":"/images/proyectos/data-center-centro-madrid.jpg","analisis-3d-ruido-carretera-zona-residencial":"/images/proyectos/analisis-3d-ruido-carretera-zona-residencial.jpg"};function g(e){return u[e]}const h=[{slug:"complejo-hidroelectrico-alto-tamega",title:"Complejo Hidroeléctrico Alto Tâmega",titleEn:"Alto Tâmega Hydroelectric Complex",tagline:"Ingeniería acústica para una de las mayores infraestructuras energéticas de Europa.",taglineEn:"Acoustic engineering for one of Europe's largest energy infrastructure projects.",sector:"Industrial",solutionType:"Control acústico integral",location:"Norte de Portugal",locationEn:"Northern Portugal",keyFigure:"1.158 MW de capacidad instalada",keyFigureEn:"1,158 MW installed capacity",technology:"Proyecto acústico integral multidisciplinar",technologyEn:"Integral multidisciplinary acoustic project",featured:!0,challenge:`El complejo hidroeléctrico de Tâmega, situado en el norte de Portugal, constituye una de las mayores iniciativas energéticas en la historia del país y una de las mayores instalaciones de almacenamiento de energía de Europa. Este sistema incluye tres presas con una capacidad instalada conjunta de 1.158 MW y dos parques eólicos que alcanzarán los 274 MW. La construcción de Tâmega ha marcado un hito en la transición hacia un modelo energético más limpio y eficiente.

La complejidad técnica del proyecto era elevada: grandes turbinas, alternadores, sistemas hidráulicos y equipos electromecánicos de alta potencia operando en entornos de elevada sensibilidad ambiental. El desafío consistía en garantizar el cumplimiento simultáneo de la normativa laboral en materia de exposición al ruido y de la normativa ambiental aplicable, tanto en el interior de las instalaciones como en su entorno.`,challengeEn:`The Tâmega hydroelectric complex, located in northern Portugal, is one of the largest energy initiatives in the country's history and one of Europe's biggest energy storage facilities. The system includes three dams with a combined installed capacity of 1,158 MW and two wind farms reaching 274 MW. The construction of Tâmega marked a milestone in the transition towards a cleaner, more efficient energy model.

The technical complexity was significant: large turbines, alternators, hydraulic systems and high-power electromechanical equipment operating in highly sensitive environmental settings. The challenge was to ensure simultaneous compliance with occupational noise exposure regulations and applicable environmental standards, both inside the facilities and in their surroundings.`,solution:`SNA Consultoría Acústica desarrolló el proyecto acústico integral orientado a la definición y recomendación de soluciones específicas para distintas zonas y focos emisores de las tres centrales: Gouvães, Daivões y Alto Tâmega.

El proyecto acústico se centró en optimizar y reducir los niveles sonoros tanto en el interior de las instalaciones como en el exterior de las mismas. Se diseñaron soluciones adaptadas a cada recinto y equipo, incorporando tratamientos absorbentes, sistemas de aislamiento, cerramientos técnicos y medidas de control de transmisión estructural.

Además de la reducción del ruido aéreo, se abordó específicamente la transmisión por vía estructural, aspecto crítico en instalaciones de gran potencia, minimizando la propagación vibratoria hacia elementos constructivos y entorno exterior.`,solutionEn:`SNA Acoustic Consultancy developed the integral acoustic project aimed at defining and recommending specific solutions for different zones and emission sources across the three power stations: Gouvães, Daivões and Alto Tâmega.

The acoustic project focused on optimising and reducing sound levels both inside and outside the facilities. Solutions were designed for each enclosure and piece of equipment, incorporating absorbent treatments, insulation systems, technical enclosures and structural transmission control measures.

Beyond airborne noise reduction, structural transmission was specifically addressed — a critical aspect in high-power installations — minimising vibratory propagation towards building elements and the exterior environment.`,result:"La intervención de SNA en el complejo Tâmega demuestra la capacidad de la firma para participar en infraestructuras energéticas estratégicas de escala internacional, integrando ingeniería acústica avanzada, sostenibilidad y cumplimiento normativo. En un proyecto donde la dimensión técnica y ambiental es máxima, SNA aportó soluciones a medida que permiten compatibilizar eficiencia energética, seguridad laboral y respeto por el entorno.",resultEn:"SNA's involvement in the Tâmega complex demonstrates the firm's capability to participate in strategic energy infrastructure at an international scale, integrating advanced acoustic engineering, sustainability and regulatory compliance. In a project where the technical and environmental dimension is at its highest, SNA provided tailored solutions that reconcile energy efficiency, occupational safety and environmental respect.",images:[]},{slug:"central-termica-castejon",title:"Central Térmica de Ciclo Combinado, Castejón",titleEn:"Combined Cycle Thermal Power Plant, Castejón",tagline:"Cerramiento acústico de alto rendimiento sobre caldera HRSG con desacoplamiento estructural completo.",taglineEn:"High-performance acoustic enclosure over HRSG boiler with full structural decoupling.",sector:"Industrial",solutionType:"Aislamiento acústico",location:"Castejón, Navarra",locationEn:"Castejón, Navarra",keyFigure:"Rw ≥ 35–40 dB de aislamiento",keyFigureEn:"Rw ≥ 35–40 dB insulation",regulation:"Ley 37/2003 del Ruido y normativa foral de Navarra",regulationEn:"Spanish Noise Law 37/2003 and Navarra regional regulations",challenge:`El objetivo prioritario de la actuación fue corregir los niveles de inmisión acústica en el entorno de la Central Térmica de Ciclo Combinado de Castejón, concretamente en las proximidades del Grupo 1 y, de manera especial, en la zona de la Caldera de Recuperación (HRSG), identificada como uno de los principales focos contribuyentes a la superación de límites en receptores sensibles del entorno.

Las evaluaciones acústicas previas evidenciaron una mayor incidencia durante el periodo nocturno, debido a la reducción del ruido de fondo, mayores exigencias normativas y condiciones de propagación más desfavorables. La actuación se diseñó para garantizar el cumplimiento de la Ley 37/2003 del Ruido y de la normativa foral aplicable en la Comunidad Foral de Navarra.`,challengeEn:`The primary objective was to correct acoustic immission levels around the Combined Cycle Thermal Power Plant of Castejón, specifically near Group 1 and, particularly, in the Heat Recovery Steam Generator (HRSG) area, identified as one of the main sources contributing to limit exceedances at sensitive receptors in the surroundings.

Previous acoustic assessments revealed greater impact during nighttime, due to lower background noise, stricter regulatory requirements and less favourable propagation conditions. The intervention was designed to ensure compliance with Spanish Noise Law 37/2003 and the applicable regional regulations of the Foral Community of Navarra.`,solution:`La solución adoptada consistió en la ejecución de un cerramiento acústico perimetral sobre la zona de caldera, compuesto por paneles modulares multicapa de alto aislamiento (chapa de acero + absorbente interior + barrera acústica + chapa perforada), con un índice estimado Rw ≥ 35–40 dB. El sistema incorporó tratamiento absorbente interior para reducir la reverberación, puertas acústicas estancas y sellado específico en encuentros e instalaciones.

Especial relevancia tuvo el diseño del desacoplamiento estructural. El cerramiento se ancló elásticamente mediante apoyos antivibratorios y láminas resilientes en todos los puntos de contacto, evitando la transmisión sólida del ruido. Asimismo, se ejecutaron nuevas zapatas de cimentación para soportar la estructura metálica, diseñadas con un sistema de amortiguación perimetral continuo mediante elastómeros de alta durabilidad y rigidez dinámica controlada.`,solutionEn:`The adopted solution consisted of a perimeter acoustic enclosure over the boiler area, composed of high-insulation multilayer modular panels (steel sheet + interior absorbent + acoustic barrier + perforated sheet), with an estimated Rw ≥ 35–40 dB. The system incorporated interior absorbent treatment to reduce reverberation, sealed acoustic doors and specific sealing at junctions and services.

The structural decoupling design was particularly important. The enclosure was elastically anchored using anti-vibration supports and resilient layers at all contact points, preventing solid-borne noise transmission. New foundation footings were also built to support the steel structure, designed with a continuous perimeter damping system using high-durability elastomers with controlled dynamic stiffness.`,result:"Este sistema permitió reducir la transmisión estructural, evitar puentes acústicos y minimizar posibles amplificaciones por resonancia, garantizando la eficacia a largo plazo en un entorno industrial exterior de alta exigencia. Se logró el cumplimiento pleno de la normativa tanto estatal como foral, eliminando las superaciones especialmente críticas durante el periodo nocturno.",resultEn:"This system reduced structural transmission, eliminated acoustic bridges and minimised possible resonance amplifications, ensuring long-term effectiveness in a demanding outdoor industrial environment. Full compliance with both national and regional regulations was achieved, eliminating the exceedances that were especially critical during the nighttime period.",images:[]},{slug:"monitorizacion-acustica-central-industrial",title:"Monitorización acústica avanzada en central industrial",titleEn:"Advanced acoustic monitoring at an industrial power plant",tagline:"Un año de monitorización continua correlacionando 40–50 parámetros operativos con el cumplimiento acústico.",taglineEn:"One year of continuous monitoring correlating 40–50 operational parameters with acoustic compliance.",sector:"Industrial",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"12 meses de monitorización, 40–50 equipos correlacionados",keyFigureEn:"12 months of monitoring, 40–50 correlated parameters",technology:"Acústica Industrial Inteligente, análisis masivo de datos",technologyEn:"Intelligent Industrial Acoustics, massive data analysis",challenge:`En el marco de un proyecto de I+D, SNA Consultoría Acústica se enfrentó al desafío de ir más allá del simple registro de niveles sonoros. El objetivo era analizar en profundidad la relación entre el funcionamiento operativo de una planta industrial y el cumplimiento normativo en el perímetro de la parcela.

La problemática no era sencilla: los incumplimientos no se debían tanto al nivel global continuo equivalente, sino a la aparición de componentes tonales, impulsivas y de baja frecuencia que activaban factores de corrección reglamentarios. Identificar con precisión qué configuraciones de funcionamiento generaban riesgo de incumplimiento requería un enfoque radicalmente distinto al convencional.`,challengeEn:`Within an R&D project, SNA Acoustic Consultancy faced the challenge of going beyond simple sound level recording. The objective was to analyse in depth the relationship between the operational functioning of an industrial plant and regulatory compliance at the site perimeter.

The issue was not straightforward: non-compliance was not so much due to the overall equivalent continuous level, but rather to the appearance of tonal, impulsive and low-frequency components that triggered regulatory correction factors. Precisely identifying which operating configurations generated non-compliance risk required a radically different approach from conventional methods.`,solution:`SNA desarrolló un sistema de monitorización acústica continua que se extendió durante un año completo, permitiendo disponer de una base de datos robusta y representativa en distintos escenarios de funcionamiento y condiciones ambientales.

De forma simultánea, se integraron datos de aproximadamente 40–50 equipos y parámetros operativos de la central, correlacionando en tiempo real el comportamiento acústico con los estados de carga, arranque, régimen parcial y condiciones específicas de operación.

El análisis posterior permitió identificar patrones claros de funcionamiento asociados a penalizaciones normativas, especialmente relacionadas con componentes de baja frecuencia e impulsividad. Se determinaron con precisión los escenarios en los que se producían superaciones en el perímetro.`,solutionEn:`SNA developed a continuous acoustic monitoring system spanning a full year, providing a robust and representative database across different operating scenarios and environmental conditions.

Simultaneously, data from approximately 40–50 pieces of equipment and operational parameters were integrated, correlating acoustic behaviour in real time with load states, start-up sequences, partial load regimes and specific operating conditions.

Subsequent analysis identified clear operating patterns associated with regulatory penalties, particularly related to low-frequency components and impulsiveness. The scenarios in which perimeter exceedances occurred were precisely determined.`,result:`Este enfoque permitió transformar una problemática aparentemente difusa en un diagnóstico cuantificado y operativo. La planta pudo identificar con exactitud qué configuraciones de funcionamiento generaban riesgo de incumplimiento, facilitando la toma de decisiones técnicas y operativas sin necesidad de sobredimensionar medidas correctoras.

Este proyecto representa la evolución hacia una Acústica Industrial Inteligente, donde la monitorización avanzada, el análisis masivo de datos y la innovación metodológica permiten anticipar incumplimientos, optimizar la operación y convertir el control acústico en una herramienta estratégica de gestión industrial.`,resultEn:`This approach transformed an apparently diffuse problem into a quantified, operational diagnosis. The plant was able to identify exactly which operating configurations generated non-compliance risk, facilitating technical and operational decisions without oversizing corrective measures.

This project represents the evolution towards Intelligent Industrial Acoustics, where advanced monitoring, massive data analysis and methodological innovation enable anticipating non-compliance, optimising operations and turning acoustic control into a strategic industrial management tool.`,images:[]},{slug:"cabinas-acusticas-fabrica-vidrio",title:"Cabinas acústicas de alto rendimiento en fábrica de vidrio",titleEn:"High-performance acoustic booths in a glass factory",tagline:"Espacios de trabajo protegidos frente a ruido, vibraciones y temperaturas extremas junto a hornos de producción.",taglineEn:"Workspaces protected from noise, vibrations and extreme temperatures alongside production furnaces.",sector:"Industrial",solutionType:"Aislamiento acústico",location:"España",locationEn:"Spain",keyFigure:"2 cabinas de alto rendimiento con solera flotante",keyFigureEn:"2 high-performance booths with floating floor",technology:"Doble panel acústico amortiguado, climatización independiente",technologyEn:"Double damped acoustic panels, independent climate control",challenge:`En un entorno de fabricación de vidrio, caracterizado por elevados niveles de ruido, vibraciones y condiciones térmicas severas asociadas a hornos y líneas de producción, se requería el diseño, fabricación, transporte e instalación de dos cabinas acústicas destinadas a albergar equipos auxiliares y sistemas de control vinculados a un nuevo horno de producción.

Estas cabinas debían funcionar como espacios de trabajo permanentes, donde los operadores supervisan de manera continua el funcionamiento del horno, controlan parámetros de producción y gestionan alarmas e incidencias del proceso. Por ello, el proyecto se abordó desde una perspectiva integral, combinando aislamiento acústico, confort térmico, seguridad estructural y cumplimiento normativo.`,challengeEn:`In a glass manufacturing environment, characterised by high noise levels, vibrations and severe thermal conditions associated with furnaces and production lines, the design, manufacture, transport and installation of two acoustic booths was required to house auxiliary equipment and control systems linked to a new production furnace.

These booths needed to function as permanent workspaces where operators continuously monitor furnace operation, control production parameters and manage process alarms and incidents. The project was therefore approached from an integral perspective, combining acoustic insulation, thermal comfort, structural safety and regulatory compliance.`,solution:`El diseño garantizó un elevado aislamiento mediante sistemas de doble panel acústico amortiguado, asegurando niveles sonoros interiores compatibles con la normativa de seguridad y salud laboral. Cada cabina incorporó climatización independiente, iluminación técnica adecuada y acristalamientos especiales con control acústico y térmico.

Dado el entorno industrial de alta exigencia, las cabinas se ejecutaron sobre solera flotante, logrando un desacoplamiento efectivo frente a las vibraciones generadas por las líneas de producción adyacentes. La solución estructural fue dimensionada para garantizar resistencia mecánica, estabilidad y durabilidad en condiciones severas.

El conjunto se diseñó y ejecutó cumpliendo estrictamente la normativa vigente en materia de seguridad estructural, protección contra incendios, seguridad y salud en el trabajo e instalaciones eléctricas en baja tensión.`,solutionEn:`The design ensured high insulation through double damped acoustic panel systems, ensuring interior sound levels compatible with occupational health and safety regulations. Each booth incorporated independent climate control, adequate technical lighting and special glazing with acoustic and thermal control.

Given the highly demanding industrial environment, the booths were built on floating floors, achieving effective decoupling from vibrations generated by adjacent production lines. The structural solution was dimensioned to guarantee mechanical resistance, stability and durability under severe conditions.

The entire assembly was designed and built in strict compliance with current regulations on structural safety, fire protection, occupational health and safety, and low-voltage electrical installations.`,result:"SNA demostró su capacidad para intervenir en fábricas de vidrio y procesos industriales de alta potencia, desarrollando soluciones acústicas y estructurales a medida que protegen al trabajador sin comprometer la operatividad del proceso productivo. Las cabinas proporcionan un entorno de trabajo seguro, confortable y plenamente operativo en condiciones industriales extremas.",resultEn:"SNA demonstrated its capability to work in glass factories and high-power industrial processes, developing bespoke acoustic and structural solutions that protect workers without compromising production process operability. The booths provide a safe, comfortable and fully operational working environment under extreme industrial conditions.",images:[]},{slug:"cubierta-edificio-exclusivo-madrid",title:"Aislamiento acústico en cubierta de edificio exclusivo en Madrid",titleEn:"Rooftop acoustic insulation on an exclusive Madrid building",tagline:"Pantallas acústicas modulares para extractores y climatización en cubierta de edificio emblemático.",taglineEn:"Modular acoustic screens for rooftop extractors and HVAC systems on a landmark building.",sector:"Arquitectónico",solutionType:"Aislamiento acústico",location:"Madrid, España",locationEn:"Madrid, Spain",keyFigure:"Pantallas multicapa en configuración 'L' y longitudinal",keyFigureEn:"Multilayer screens in 'L' and longitudinal configuration",regulation:"OPCAT del Ayuntamiento de Madrid (2011)",regulationEn:"Madrid City Council OPCAT (2011)",challenge:`SNA Consultoría Acústica abordó la definición y diseño de medidas correctoras de aislamiento acústico en la cubierta de un edificio emblemático de Madrid, con el objetivo de reducir el ruido generado por extractores de cocina y maquinaria de climatización situados en planta superior.

La intervención estuvo orientada a minimizar la transmisión sonora hacia las viviendas ubicadas en plantas inferiores, prestando especial atención a la componente de baja frecuencia característica de este tipo de instalaciones. El proyecto se diseñó para garantizar el cumplimiento de la Ordenanza de Protección contra la Contaminación Acústica y Térmica del Ayuntamiento de Madrid (OPCAT, 2011).`,challengeEn:`SNA Acoustic Consultancy addressed the definition and design of corrective acoustic insulation measures on the rooftop of a landmark building in Madrid, aiming to reduce noise generated by kitchen extractors and HVAC machinery located on the upper level.

The intervention focused on minimising sound transmission towards apartments on lower floors, with particular attention to the low-frequency component characteristic of these installations. The project was designed to ensure compliance with the Madrid City Council Ordinance on Protection against Acoustic and Thermal Pollution (OPCAT, 2011).`,solution:`La solución consistió en la ejecución de apantallamientos acústicos modulares de alto rendimiento. Para los extractores de cocina se diseñó una pantalla en configuración en "L", optimizada para interceptar la propagación directa del ruido hacia los receptores más sensibles. En el caso de la maquinaria de climatización, se ejecutó una pantalla de mayor desarrollo longitudinal, cubriendo el frente principal de las unidades y manteniendo registros practicables que garantizan la accesibilidad para mantenimiento.

Los sistemas se construyeron mediante paneles multicapa desmontables de alto aislamiento y absorción acústica, compuestos por chapa de acero galvanizado, núcleo de lana de roca de alta densidad y acabado interior perforado para optimizar el rendimiento absorbente. La estructura se rigidizó mediante perfiles metálicos y anclajes específicos, asegurando estabilidad frente a viento y evitando vibraciones o resonancias indeseadas.`,solutionEn:`The solution consisted of high-performance modular acoustic screens. For the kitchen extractors, an "L"-shaped screen was designed, optimised to intercept direct noise propagation towards the most sensitive receptors. For the HVAC machinery, a screen with greater longitudinal extent was installed, covering the main front of the units while maintaining accessible panels for maintenance.

The systems were built using demountable multilayer panels with high insulation and acoustic absorption, composed of galvanised steel sheet, high-density rock wool core and perforated interior finish to optimise absorbent performance. The structure was stiffened with steel profiles and specific anchors, ensuring wind stability and avoiding unwanted vibrations or resonances.`,result:"El resultado fue una solución técnicamente eficaz, estructuralmente segura y plenamente integrada en el entorno urbano, compatibilizando instalaciones técnicas en cubierta con la protección acústica de uso residencial de alta exigencia en cumplimiento de la normativa municipal vigente.",resultEn:"The result was a technically effective, structurally safe solution fully integrated into the urban environment, reconciling rooftop technical installations with high-standard residential acoustic protection in compliance with current municipal regulations.",images:[]},{slug:"conservatorio-musica-edificio-historico",title:"Conservatorio de música: precisión sonora en edificio histórico",titleEn:"Music conservatory: sonic precision in a heritage building",tagline:"Aislamiento y acondicionamiento a medida para cada instrumento en un edificio patrimonial protegido.",taglineEn:"Bespoke insulation and conditioning for each instrument within a protected heritage building.",sector:"Arquitectónico",solutionType:"Acondicionamiento acústico",location:"España",locationEn:"Spain",keyFigure:"Sala de conciertos polivalente + aulas diferenciadas por instrumento",keyFigureEn:"Multipurpose concert hall + instrument-specific classrooms",regulation:"CTE + criterios específicos por uso musical",regulationEn:"Spanish Building Code (CTE) + specific musical use criteria",challenge:`El proyecto acústico se desarrolló en el marco de la reforma de un conservatorio de música ubicado en un edificio histórico, lo que implicó importantes limitaciones constructivas derivadas de la protección patrimonial. Las soluciones adoptadas debían ser compatibles con la conservación del inmueble, condicionando espesores, sistemas constructivos y posibilidades de intervención estructural.

El diseño no se limitó al cumplimiento del CTE, sino que tuvo en cuenta las particularidades de emisión de cada instrumento: no requieren el mismo tratamiento las aulas de percusión o batería —con altos niveles y bajas frecuencias— que las de tuba o flauta. Esto obligó a ajustar soluciones de aislamiento y tiempos de reverberación según el uso específico de cada espacio.`,challengeEn:`The acoustic project was developed as part of the renovation of a music conservatory located in a historic building, which imposed significant construction constraints due to heritage protection. The solutions had to be compatible with the building's preservation, conditioning thicknesses, construction systems and structural intervention possibilities.

The design went beyond CTE compliance, taking into account the emission characteristics of each instrument: percussion or drum rooms — with high levels and low frequencies — require very different treatment from tuba or flute rooms. This required adjusting insulation solutions and reverberation times according to the specific use of each space.`,solution:`La actuación abordó tanto el aislamiento acústico entre recintos como el acondicionamiento interior de las aulas, garantizando también la protección de espacios sensibles como la biblioteca y las salas de estudio.

El complejo incorpora además una sala de conciertos polivalente, para la que se realizó un estudio acústico específico con el fin de optimizar su respuesta para distintos tipos de interpretación. Asimismo, se otorgó especial relevancia al control del ruido de instalaciones, estableciendo criterios estrictos para evitar que climatización y ventilación interfieran en la práctica y la calidad sonora del conjunto del edificio.`,solutionEn:`The intervention addressed both acoustic insulation between rooms and interior conditioning of classrooms, also ensuring the protection of sensitive spaces such as the library and study rooms.

The complex also includes a multipurpose concert hall, for which a specific acoustic study was carried out to optimise its response for different types of performance. Special attention was given to building services noise control, establishing strict criteria to prevent HVAC systems from interfering with musical practice and the overall sonic quality of the building.`,result:"Se lograron aislamiento y reverberación optimizados para cada espacio según su uso musical específico, todo ello compatible con la protección patrimonial del edificio. La sala polivalente ofrece una respuesta acústica adecuada para distintos tipos de interpretación, y el control de ruido de instalaciones garantiza que ningún sistema técnico interfiere en la actividad musical del conservatorio.",resultEn:"Optimised insulation and reverberation were achieved for each space according to its specific musical use, all compatible with the heritage protection of the building. The multipurpose hall offers an adequate acoustic response for different types of performance, and building services noise control ensures that no technical system interferes with the conservatory's musical activities.",images:[]},{slug:"silenciador-fem-soplantes-depuradora",title:"Silenciador industrial mediante modelización FEM para soplantes de alto caudal",titleEn:"Industrial silencer via FEM modelling for high-flow blowers",tagline:"Diseño optimizado por elementos finitos para equilibrar atenuación acústica y eficiencia aerodinámica en una depuradora.",taglineEn:"FEM-optimised design balancing acoustic attenuation and aerodynamic efficiency at a wastewater treatment plant.",sector:"Medioambiental",solutionType:"Simulación y diseño FEM",location:"España",locationEn:"Spain",keyFigure:"Modelización FEM con COMSOL Multiphysics",keyFigureEn:"FEM modelling with COMSOL Multiphysics",technology:"Simulación acústica, aerodinámica y mecánica simultánea",technologyEn:"Simultaneous acoustic, aerodynamic and mechanical simulation",challenge:`El proyecto consistió en el diseño específico de un silenciador para las soplantes de una planta depuradora, con el objetivo de reducir los elevados niveles de ruido generados por estos equipos sin comprometer su rendimiento operativo. La actuación presentaba una complejidad técnica significativa debido al alto nivel sonoro en origen y al gran caudal de aire impulsado, lo que obligaba a minimizar las pérdidas de carga y garantizar simultáneamente una atenuación acústica eficaz.

Uno de los principales retos fue compatibilizar tres variables críticas: reducción sonora, eficiencia aerodinámica y resistencia estructural. En este tipo de instalaciones, una solución sobredimensionada puede comprometer el funcionamiento de la soplante, mientras que una solución ligera puede resultar insuficiente desde el punto de vista acústico o mecánico.`,challengeEn:`The project involved the specific design of a silencer for the blowers of a wastewater treatment plant, aiming to reduce the high noise levels generated by this equipment without compromising its operational performance. The intervention presented significant technical complexity due to the high source sound level and the large air flow rate, requiring minimised pressure losses while simultaneously ensuring effective acoustic attenuation.

One of the main challenges was reconciling three critical variables: noise reduction, aerodynamic efficiency and structural resistance. In these installations, an oversized solution can compromise blower performance, while a lightweight solution may be insufficient from an acoustic or mechanical standpoint.`,solution:`Para optimizar el diseño, se emplearon herramientas de simulación avanzada mediante el método de los elementos finitos (FEM) con COMSOL Multiphysics. Estas simulaciones permitieron analizar la propagación sonora en el interior del silenciador, estudiar posibles fenómenos de resonancia, evaluar la distribución de velocidades y estimar las pérdidas de carga. Asimismo, se verificó el comportamiento mecánico del conjunto frente a esfuerzos dinámicos y condiciones reales de operación.

A partir de los modelos numéricos se ajustaron geometrías internas, configuraciones de bafles y materiales absorbentes hasta alcanzar un equilibrio óptimo entre atenuación acústica, eficiencia de flujo y robustez constructiva.`,solutionEn:`To optimise the design, advanced simulation tools based on the Finite Element Method (FEM) with COMSOL Multiphysics were used. These simulations enabled analysis of sound propagation inside the silencer, study of potential resonance phenomena, evaluation of velocity distribution and estimation of pressure losses. The mechanical behaviour of the assembly under dynamic loads and real operating conditions was also verified.

Based on the numerical models, internal geometries, baffle configurations and absorbent materials were adjusted until an optimal balance was achieved between acoustic attenuation, flow efficiency and structural robustness.`,result:"El resultado fue una solución totalmente adaptada a las condiciones específicas de la instalación, técnicamente validada antes de su fabricación. La modelización predictiva permitió diseñar una solución más eficiente, reducir incertidumbres y optimizar costes antes de la ejecución, reflejando el valor de la ingeniería acústica basada en simulación avanzada.",resultEn:"The result was a solution fully tailored to the specific conditions of the installation, technically validated before manufacture. The predictive modelling enabled a more efficient design, reduced uncertainties and optimised costs before execution, reflecting the value of acoustic engineering based on advanced simulation.",images:[]},{slug:"ruido-estructural-data-center-comsol",title:"Análisis de ruido estructural en Data Center con múltiples grupos electrógenos",titleEn:"Structural noise analysis in a Data Centre with multiple generator sets",tagline:"Modelización FEM que reveló cómo estructuras de hormigón de gran masa actúan como 'altavoces estructurales'.",taglineEn:"FEM modelling revealed how high-mass concrete structures act as 'structural loudspeakers'.",sector:"Industrial",solutionType:"Simulación y diseño FEM",location:"España",locationEn:"Spain",keyFigure:"Múltiples grupos electrógenos sobre bancadas de hormigón",keyFigureEn:"Multiple generator sets on concrete plinths",technology:"FEM con COMSOL Multiphysics",technologyEn:"FEM with COMSOL Multiphysics",challenge:`El proyecto consistió en el análisis avanzado del ruido estructural generado por varios grupos electrógenos instalados en un edificio destinado a Data Center, con el objetivo de evaluar la transmisión vibratoria hacia otras zonas del inmueble y justificar técnicamente la necesidad de medidas correctoras específicas.

En este tipo de infraestructuras críticas, donde coexisten múltiples grupos electrógenos de elevada potencia sobre bancadas de hormigón de gran masa, el riesgo no se limita al ruido aéreo directo, sino a la transmisión estructural de vibraciones a través de forjados, pilares y elementos portantes. Aunque la elevada masa estructural podría sugerir un comportamiento acústico favorable, el estudio demostró que, bajo determinadas frecuencias de excitación, estas superficies pueden comportarse como verdaderos radiadores sonoros, actuando como "altavoces estructurales" y amplificando el ruido más allá de lo inicialmente previsto.`,challengeEn:`The project involved the advanced analysis of structural noise generated by several generator sets installed in a Data Centre building, aiming to evaluate vibratory transmission to other areas of the building and technically justify the need for specific corrective measures.

In this type of critical infrastructure, where multiple high-power generator sets coexist on high-mass concrete plinths, the risk is not limited to direct airborne noise but extends to the structural transmission of vibrations through floor slabs, columns and load-bearing elements. Although the high structural mass might suggest favourable acoustic behaviour, the study demonstrated that, at certain excitation frequencies, these surfaces can behave as true sound radiators, acting as "structural loudspeakers" and amplifying noise beyond initial expectations.`,solution:"Para el análisis se desarrolló un modelo mediante el método de los elementos finitos (FEM) utilizando COMSOL Multiphysics, que permitió simular con alta precisión la interacción dinámica entre los grupos electrógenos, las bancadas de hormigón y la estructura global del edificio. El modelo permitió visualizar modos propios, amplitudes de desplazamiento y propagación vibratoria, identificando las frecuencias críticas donde el fenómeno de radiación acústica estructural resultaba más significativo.",solutionEn:"A Finite Element Method (FEM) model was developed using COMSOL Multiphysics, enabling high-precision simulation of the dynamic interaction between the generator sets, concrete plinths and the building's overall structure. The model visualised eigenmodes, displacement amplitudes and vibratory propagation, identifying the critical frequencies where structural acoustic radiation was most significant.",result:"Los resultados evidenciaron que, sin sistemas adecuados de aislamiento, la energía vibratoria podía inducir niveles de ruido apreciables en recintos técnicos y zonas sensibles del edificio, incluso alejadas de la sala de grupos. Esta evidencia justificó la incorporación de soluciones de desacoplamiento y amortiguamiento diseñadas específicamente para minimizar la transmisión estructural y evitar que superficies de gran masa actúen como emisores secundarios de ruido. Un ejemplo de ingeniería acústica predictiva aplicada a entornos tecnológicos de alta criticidad.",resultEn:"The results demonstrated that, without adequate isolation systems, vibratory energy could induce appreciable noise levels in technical rooms and sensitive areas of the building, even distant from the generator room. This evidence justified the incorporation of decoupling and damping solutions specifically designed to minimise structural transmission and prevent high-mass surfaces from acting as secondary noise emitters. An example of predictive acoustic engineering applied to high-criticality technological environments.",images:[]},{slug:"sala-calderas-colindante-dormitorio",title:"Sala de calderas colindante a dormitorio: resolución judicial",titleEn:"Boiler room adjacent to a bedroom: judicial resolution",tagline:"El 95% del problema no era ruido aéreo, sino transmisión estructural. Un diagnóstico preciso cerró el proceso legal.",taglineEn:"95% of the problem was not airborne noise but structural transmission. A precise diagnosis closed the legal case.",sector:"Arquitectónico",solutionType:"Control de vibraciones",location:"España",locationEn:"Spain",keyFigure:"95% de transmisión por vía estructural",keyFigureEn:"95% of transmission via structural path",challenge:`La intervención se desarrolló en una sala de calderas afectada por una sentencia judicial debido a problemas de ruido en una vivienda colindante, concretamente en un dormitorio situado pared con pared con la sala técnica. La proximidad hacía especialmente sensible cualquier transmisión sonora o vibratoria.

En una primera fase se realizaron mediciones acústicas exhaustivas, comprobándose que el aislamiento a ruido aéreo entre ambos recintos era suficiente para los niveles generados en el interior. Este resultado descartó la necesidad de reforzar cerramientos, evidenciando que más del 95% de la transmisión se producía por vía estructural. El diagnóstico técnico corrigió así la idea inicial de actuar sobre el aislamiento aéreo, evitando una inversión innecesaria y poco eficaz.`,challengeEn:`The intervention took place in a boiler room affected by a court ruling due to noise problems in an adjacent dwelling, specifically in a bedroom located wall-to-wall with the technical room. The proximity made any sound or vibratory transmission especially sensitive.

In a first phase, exhaustive acoustic measurements were carried out, confirming that the airborne sound insulation between both rooms was sufficient for the levels generated inside. This result ruled out the need to reinforce enclosures, evidencing that over 95% of the transmission occurred via the structural path. The technical diagnosis thus corrected the initial idea of acting on airborne insulation, avoiding an unnecessary and ineffective investment.`,solution:`La solución se centró en el control de vibraciones. Se diseñaron y calcularon bancadas antivibratorias específicas en función de los pesos y frecuencias de funcionamiento de bombas y calderas, garantizando una frecuencia propia adecuada y un correcto desacoplamiento dinámico.

Asimismo, se amortiguaron y desacoplaron todas las redes de conductos y conexiones rígidas susceptibles de transmitir energía vibratoria a la estructura del edificio. De forma complementaria, se sustituyeron determinados equipos por otros más eficientes energéticamente, mejorando el rendimiento global de la instalación.`,solutionEn:`The solution focused on vibration control. Specific anti-vibration plinths were designed and calculated based on the weights and operating frequencies of pumps and boilers, ensuring an adequate natural frequency and correct dynamic decoupling.

All duct networks and rigid connections susceptible to transmitting vibratory energy to the building structure were also damped and decoupled. Additionally, certain equipment was replaced with more energy-efficient alternatives, improving the overall performance of the installation.`,result:"Tras la ejecución de las medidas correctoras, las mediciones de verificación confirmaron que el funcionamiento de la sala de calderas resulta acústicamente inapreciable en el dormitorio colindante, cumpliéndose plenamente los objetivos técnicos y quedando cerrado el proceso legal. Este proyecto demuestra la importancia del diagnóstico acústico riguroso y del enfoque estructural en problemas de transmisión compleja, donde la clave no está en añadir masa, sino en desacoplar correctamente la fuente.",resultEn:"Following execution of the corrective measures, verification measurements confirmed that boiler room operation is acoustically imperceptible in the adjacent bedroom, fully meeting technical objectives and closing the legal proceedings. This project demonstrates the importance of rigorous acoustic diagnosis and a structural approach in complex transmission problems, where the key is not adding mass but correctly decoupling the source.",images:[]},{slug:"elevador-coches-entorno-residencial",title:"Elevador de coches en entorno residencial",titleEn:"Car lift in a residential setting",tagline:"Reducción superior a 20 dB actuando exclusivamente sobre los anclajes laterales de la plataforma.",taglineEn:"Over 20 dB reduction by acting solely on the platform's lateral anchors.",sector:"Arquitectónico",solutionType:"Control de vibraciones",location:"Madrid, España",locationEn:"Madrid, Spain",keyFigure:"> 20 dB de reducción en vivienda colindante",keyFigureEn:"> 20 dB reduction in the adjacent dwelling",challenge:`La actuación se desarrolló en una instalación de elevador hidráulico de vehículos en Madrid, donde la plataforma se eleva mediante pistón hidráulico y se guía a través de anclajes laterales a los paramentos estructurales del edificio.

Aunque en este tipo de sistemas la principal afección acústica suele estar asociada a la transmisión vibratoria del pistón por la inyección de aceite, en este caso el problema se originaba en un ligero balanceo de la plataforma durante la entrada y salida de los vehículos. La transmisión por vía aérea era prácticamente inexistente, incluso estando sobre la propia plataforma; sin embargo, el movimiento se amplificaba estructuralmente y se propagaba a través de los elementos constructivos, generando molestias significativas en la vivienda colindante.

El análisis técnico reveló una situación especialmente compleja: una de las paredes laterales era mayoritariamente de hormigón, mientras que la otra estaba constituida por fábrica de ladrillo hueco, de menor masa y mayor susceptibilidad vibratoria. Esta asimetría condicionaba la transmisión estructural y hacía más delicada la intervención. La implantación de una estructura auxiliar completamente desacoplada resultaba poco viable desde el punto de vista técnico y de seguridad de la instalación.`,challengeEn:`The intervention took place at a hydraulic vehicle lift installation in Madrid, where the platform is raised by a hydraulic piston and guided through lateral anchors attached to the building's structural walls.

Although in these systems the main acoustic impact is usually associated with vibratory transmission from the piston through oil injection, in this case the problem originated from a slight swaying of the platform during vehicle entry and exit. Airborne transmission was practically non-existent, even standing on the platform itself; however, the movement was structurally amplified and propagated through building elements, causing significant disturbance in the adjacent dwelling.

The technical analysis revealed a particularly complex situation: one side wall was predominantly concrete, while the other consisted of hollow brick masonry with lower mass and greater vibratory susceptibility. This asymmetry conditioned the structural transmission and made the intervention more delicate. Installing a fully decoupled auxiliary structure was not viable from a technical and safety standpoint.`,solution:"La solución se centró en el punto crítico de transmisión: los anclajes laterales. Se diseñó e instaló un sistema antivibratorio específico en las uniones entre la plataforma y los paramentos, logrando interrumpir la transmisión directa de energía vibratoria hacia los elementos estructurales solidarios con la vivienda.",solutionEn:"The solution focused on the critical transmission point: the lateral anchors. A specific anti-vibration system was designed and installed at the joints between the platform and the walls, successfully interrupting the direct transmission of vibratory energy to structural elements connected to the dwelling.",result:"Las mediciones posteriores confirmaron una reducción superior a 20 dB en el nivel de ruido percibido en el interior de la vivienda colindante, resolviendo de forma eficaz el problema sin comprometer la estabilidad ni la seguridad del elevador. Este proyecto evidencia cómo, en problemas de vibración estructural, el control preciso del punto de transmisión puede resultar mucho más eficaz que intervenciones globales o sobredimensionadas.",resultEn:"Subsequent measurements confirmed a reduction of over 20 dB in the noise level perceived inside the adjacent dwelling, effectively resolving the problem without compromising the lift's stability or safety. This project demonstrates how, in structural vibration problems, precise control of the transmission point can be far more effective than global or oversized interventions.",images:[]},{slug:"local-emblematico-asturias",title:"Tratamiento acústico absorbente en local emblemático de Asturias",titleEn:"Absorbent acoustic treatment in an iconic Asturian venue",tagline:"Absorción acústica completamente invisible, integrada en la estética histórica del local.",taglineEn:"Completely invisible acoustic absorption, integrated into the venue's historic aesthetic.",sector:"Arquitectónico",solutionType:"Acondicionamiento acústico",location:"Asturias, España",locationEn:"Asturias, Spain",keyFigure:"Intervención 100% imperceptible al público",keyFigureEn:"100% imperceptible intervention to the public",technology:"Soluciones absorbentes a medida con acabados históricos",technologyEn:"Custom absorbent solutions with historic finishes",challenge:`Uno de los proyectos más singulares desarrollados por SNA ha consistido en la intervención acústica de un local emblemático en Asturias, reconocido no solo por su actividad, sino por su importante valor histórico y estético dentro del entorno urbano.

El principal reto del proyecto no era únicamente técnico, sino arquitectónico y emocional. El recinto posee una identidad visual muy consolidada, con una decoración característica que forma parte de su esencia y de la experiencia del público. La incorporación de soluciones absorbentes convencionales habría supuesto una alteración agresiva de su imagen, comprometiendo el carácter original del espacio.`,challengeEn:`One of SNA's most singular projects involved the acoustic intervention of an iconic venue in Asturias, recognised not only for its activity but for its important historical and aesthetic value within the urban environment.

The main challenge was not merely technical, but architectural and emotional. The venue has a very consolidated visual identity, with characteristic decoration that is part of its essence and the public's experience. Incorporating conventional absorbent solutions would have aggressively altered its image, compromising the original character of the space.`,solution:"Para resolver esta situación, se diseñó una estrategia de integración total. En lugar de introducir elementos acústicos visibles, se actuó sobre los acabados superficiales del recinto, reproduciendo fielmente la estética original del local. Se desarrollaron soluciones absorbentes que mantienen la misma apariencia, texturas y acabados históricos, garantizando que la intervención resultara imperceptible para el visitante.",solutionEn:"To resolve this, a total integration strategy was designed. Instead of introducing visible acoustic elements, the surface finishes of the venue were modified, faithfully reproducing its original aesthetic. Absorbent solutions were developed that maintain the same appearance, textures and historic finishes, ensuring the intervention was imperceptible to visitors.",result:"El resultado ha sido la mejora significativa del confort acústico interior —reducción de tiempos de reverberación y mejora de la inteligibilidad— sin alterar en ningún momento la identidad visual del espacio. Los elementos absorbentes quedaron completamente ocultos a la vista del público, demostrando que es posible compatibilizar patrimonio, diseño y alto rendimiento acústico. Una intervención donde la ingeniería acústica integra tecnología, creatividad y sensibilidad arquitectónica para ofrecer resultados diferenciales.",resultEn:"The result was a significant improvement in interior acoustic comfort — reduced reverberation times and improved intelligibility — without altering the visual identity of the space at any point. The absorbent elements were completely hidden from public view, demonstrating that it is possible to reconcile heritage, design and high acoustic performance. An intervention where acoustic engineering integrates technology, creativity and architectural sensitivity to deliver differentiated results.",images:[]},{slug:"edificios-residenciales-vibraciones-ferrocarril",title:"Edificios residenciales afectados por vibraciones de ferrocarril",titleEn:"Residential buildings affected by railway vibrations",tagline:"Tres edificios protegidos por SNA mientras el resto de la zona acumula incumplimientos por vibraciones del tren.",taglineEn:"Three buildings protected by SNA while the rest of the area accumulates non-compliance due to train vibrations.",sector:"Arquitectónico",solutionType:"Control de vibraciones",location:"España",locationEn:"Spain",keyFigure:"3 edificios protegidos vs. resto con incumplimientos del CTE",keyFigureEn:"3 protected buildings vs. rest with CTE non-compliance",technology:"Medición de aceleración + diseño preventivo en cimentación",technologyEn:"Acceleration measurement + preventive foundation design",challenge:`En el ámbito de la edificación residencial, SNA desarrolló uno de los trabajos más representativos en materia de análisis vibratorio y diseño preventivo frente a afecciones ferroviarias.

El proyecto se inició con una campaña de mediciones de aceleración de vibraciones en el terreno, en una zona urbana afectada por la entrada del ferrocarril a la ciudad. El análisis detallado puso de manifiesto que, con el paso de determinados trenes de mercancías, los niveles vibratorios transmitidos al terreno eran significativamente elevados, con potencial afección a futuras edificaciones residenciales tanto en términos de confort como de cumplimiento normativo.`,challengeEn:`In the field of residential construction, SNA carried out one of its most representative projects in vibration analysis and preventive design against railway impacts.

The project began with a campaign of ground vibration acceleration measurements in an urban area affected by the railway's entry into the city. Detailed analysis revealed that, with the passage of certain freight trains, the vibration levels transmitted to the ground were significantly high, with potential impact on future residential buildings both in terms of comfort and regulatory compliance.`,solution:"A partir de estos resultados, SNA planteó a diversos promotores de la zona la necesidad de incorporar soluciones específicas de aislamiento antivibratorio en fase de proyecto. Se diseñaron tratamientos estructurales adaptados a cada edificio —sistemas de desacoplamiento y soluciones de mitigación en cimentación— con el objetivo de reducir la transmisión de vibraciones al interior de las viviendas y anticiparse a posibles reclamaciones por parte de los futuros propietarios.",solutionEn:"Based on these results, SNA proposed to several developers in the area the need to incorporate specific anti-vibration isolation solutions at the design stage. Structural treatments adapted to each building were designed — decoupling systems and mitigation solutions in foundations — aiming to reduce vibration transmission into dwellings and anticipate potential claims from future owners.",result:"Esta actuación preventiva resultó determinante. Con el paso de los años, se ha constatado que, salvo los tres edificios que incorporaron los tratamientos diseñados por SNA, el resto de promociones ejecutadas en la zona han sido objeto de reiteradas incidencias y publicaciones por incumplimientos relacionados con las exigencias del Código Técnico de la Edificación en materia de ruido y vibraciones derivadas del tráfico ferroviario. Un ejemplo de ingeniería acústica como herramienta estratégica en la edificación, donde la medición real, el análisis técnico riguroso y el diseño innovador de soluciones estructurales transforman un riesgo potencial en garantía de calidad constructiva y seguridad jurídica para el promotor.",resultEn:"This preventive action proved decisive. Over the years, it has been confirmed that, apart from the three buildings that incorporated the treatments designed by SNA, the rest of the developments built in the area have been subject to repeated incidents and publications for non-compliance with the Spanish Building Code requirements regarding noise and vibrations from railway traffic. An example of acoustic engineering as a strategic tool in construction, where real measurement, rigorous technical analysis and innovative structural solution design transform a potential risk into a guarantee of construction quality and legal certainty for the developer.",images:[]},{slug:"platos-television-parlamento-europeo",title:"Platós de televisión del Parlamento Europeo",titleEn:"Television studios at the European Parliament",tagline:"Desarrollo de un material absorbente a medida para el hall central del Parlamento Europeo.",taglineEn:"Development of a custom absorbent material for the European Parliament's central hall.",sector:"Arquitectónico",solutionType:"Acondicionamiento acústico",location:"Parlamento Europeo",locationEn:"European Parliament",keyFigure:"Material acústico no comercial, diseñado específicamente",keyFigureEn:"Non-commercial acoustic material, purpose-designed",technology:"Desarrollo propio de material absorbente con acabados arquitectónicos",technologyEn:"In-house development of absorbent material with architectural finishes",featured:!0,challenge:`SNA Consultoría Acústica abordó el diseño del tratamiento absorbente de los platós de televisión ubicados en el hall central del Parlamento Europeo, uno de los espacios institucionales más representativos y arquitectónicamente exigentes del entorno europeo.

La complejidad del proyecto radicaba en la singularidad del emplazamiento. Los estudios se encuentran integrados en el gran vestíbulo central del Parlamento, un espacio abierto, de gran volumen y con una fuerte carga simbólica y estética. Cualquier intervención acústica debía garantizar el máximo rendimiento técnico sin alterar la identidad arquitectónica ni la imagen institucional del entorno.`,challengeEn:`SNA Acoustic Consultancy undertook the design of the absorbent treatment for the television studios located in the central hall of the European Parliament, one of the most representative and architecturally demanding institutional spaces in Europe.

The project's complexity lay in the uniqueness of the location. The studios are integrated into the Parliament's grand central lobby, an open, high-volume space with strong symbolic and aesthetic significance. Any acoustic intervention had to guarantee maximum technical performance without altering the architectural identity or institutional image of the environment.`,solution:"Ante esta situación, las soluciones comerciales convencionales resultaban insuficientes tanto desde el punto de vista técnico como estético. Por ello, SNA desarrolló un proyecto acústico específico en el que se definieron soluciones absorbentes a medida, incluyendo el desarrollo de un nuevo material con propiedades acústicas optimizadas y acabados adaptados al lenguaje arquitectónico del edificio.",solutionEn:"In this context, conventional commercial solutions were insufficient from both a technical and aesthetic standpoint. SNA therefore developed a specific acoustic project defining bespoke absorbent solutions, including the development of a new material with optimised acoustic properties and finishes adapted to the building's architectural language.",result:"El resultado fue la implementación de un sistema de tratamiento no comercial, diseñado específicamente para este entorno, capaz de controlar la reverberación y mejorar la calidad sonora en retransmisiones televisivas, integrándose de manera armónica en un espacio de altísima exigencia estética e institucional. Un proyecto que refleja la capacidad de ir más allá del catálogo estándar, desarrollando soluciones propias cuando el entorno lo exige, combinando innovación material, diseño acústico avanzado y sensibilidad arquitectónica.",resultEn:"The result was the implementation of a non-commercial treatment system, specifically designed for this environment, capable of controlling reverberation and improving sound quality in television broadcasts while harmoniously integrating into a space of the highest aesthetic and institutional standards. A project that reflects the ability to go beyond the standard catalogue, developing proprietary solutions when the environment demands it, combining material innovation, advanced acoustic design and architectural sensitivity.",images:[]},{slug:"fabricas-incumplimientos-acusticos",title:"Fábricas con incumplimientos acústicos: identificación precisa de focos críticos",titleEn:"Factories with acoustic non-compliance: precise identification of critical sources",tagline:"Diagnóstico selectivo que identificó los focos realmente responsables y redujo drásticamente la inversión correctora.",taglineEn:"Selective diagnosis that identified the truly responsible sources and drastically reduced corrective investment.",sector:"Industrial",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"Reducción sustancial de inversión correctora",keyFigureEn:"Substantial reduction in corrective investment",technology:"Acústica Industrial Avanzada, análisis espacial, mediciones direccionales",technologyEn:"Advanced Industrial Acoustics, spatial analysis, directional measurements",challenge:`En el ámbito industrial, uno de los principales desafíos acústicos es la coexistencia de múltiples fuentes de ruido operando simultáneamente, ubicadas a distintas alturas, en diferentes recintos y con tipologías muy variadas. Esta complejidad dificulta enormemente la identificación precisa de los focos responsables del incumplimiento normativo en el exterior.

SNA intervino en una planta industrial que presentaba afecciones significativas en los niveles sonoros medidos en el entorno exterior, superando los límites establecidos por la normativa aplicable. La dificultad no residía únicamente en el nivel global emitido, sino en la interacción combinada de equipos, estructuras, transmisiones indirectas y fenómenos de propagación complejos.`,challengeEn:`In the industrial sphere, one of the main acoustic challenges is the coexistence of multiple noise sources operating simultaneously, located at different heights, in different enclosures and with very varied typologies. This complexity greatly hinders the precise identification of the sources responsible for regulatory non-compliance externally.

SNA intervened at an industrial plant that showed significant impacts on sound levels measured in the surrounding environment, exceeding the limits established by applicable regulations. The difficulty lay not only in the overall emitted level but in the combined interaction of equipment, structures, indirect transmissions and complex propagation phenomena.`,solution:"Dentro de la línea de Acústica Industrial Avanzada, se desarrolló una metodología específica que permitió identificar con precisión la posición y contribución individual de cada punto conflictivo hacia el exterior. Mediante técnicas de análisis espacial, mediciones direccionales de alta resolución y modelización acústica detallada, se logró discriminar qué focos eran realmente determinantes en el incumplimiento normativo.",solutionEn:"Within the Advanced Industrial Acoustics line, a specific methodology was developed that precisely identified the position and individual contribution of each problematic point towards the exterior. Through spatial analysis techniques, high-resolution directional measurements and detailed acoustic modelling, it was possible to discriminate which sources were truly decisive in regulatory non-compliance.",result:"Este enfoque permitió optimizar de forma sustancial las medidas correctoras. En lugar de aplicar soluciones generalizadas y económicamente sobredimensionadas, se actuó exclusivamente sobre las fuentes críticas, reduciendo la inversión necesaria y maximizando la eficacia técnica de las actuaciones. La ingeniería dejó de ser reactiva para convertirse en estratégica: diagnóstico preciso, análisis cuantificado y diseño selectivo de soluciones donde innovación metodológica, control técnico y optimización económica convergen para transformar un problema complejo en una intervención eficiente y sostenible.",resultEn:"This approach substantially optimised the corrective measures. Instead of applying generalised and economically oversized solutions, action was taken exclusively on critical sources, reducing the necessary investment and maximising the technical effectiveness of the interventions. Engineering shifted from reactive to strategic: precise diagnosis, quantified analysis and selective solution design where methodological innovation, technical control and economic optimisation converge to transform a complex problem into an efficient, sustainable intervention.",images:[]},{slug:"chimeneas-hosteleria-centro-comercial",title:"Chimeneas de hostelería en centro comercial bajo edificios residenciales",titleEn:"Restaurant chimneys in a shopping centre beneath residential buildings",tagline:"14 líneas de chimeneas atravesando una torre residencial sin generar una sola molestia.",taglineEn:"14 chimney lines running through a residential tower without generating a single complaint.",sector:"Arquitectónico",solutionType:"Aislamiento acústico",location:"España",locationEn:"Spain",keyFigure:"14 líneas de chimeneas, cero molestias registradas",keyFigureEn:"14 chimney lines, zero complaints recorded",technology:"Modelización acústica + control vibratorio integral",technologyEn:"Acoustic modelling + integral vibration control",challenge:`La implantación de zonas de restauración en grandes centros comerciales ubicados bajo edificios residenciales supone uno de los escenarios más complejos en ingeniería acústica urbana. SNA abordó la problemática generada por las salidas de humos de una amplia zona de hostelería situada en una planta inferior de un centro comercial integrado en una ciudad de gran relevancia.

El sistema estaba compuesto por 14 líneas de chimeneas, algunas de hasta un metro de diámetro, que discurrían verticalmente por el patinillo interior de una de las torres residenciales. Esta configuración generaba un riesgo elevado tanto de transmisión de ruido aéreo como de vibraciones estructurales hacia las viviendas superiores.`,challengeEn:`The installation of restaurant areas in large shopping centres located beneath residential buildings represents one of the most complex scenarios in urban acoustic engineering. SNA addressed the problems generated by the exhaust outlets of a large restaurant area situated on a lower level of a shopping centre integrated into a major city.

The system comprised 14 chimney lines, some up to one metre in diameter, running vertically through the service shaft of one of the residential towers. This configuration generated a high risk of both airborne noise transmission and structural vibrations to the upper dwellings.`,solution:`La intervención requirió un análisis integral que combinó modelización acústica avanzada, cálculos específicos de propagación sonora y estudio detallado de la transmisión vibratoria a través de forjados y estructuras portantes. No se trataba únicamente de atenuar niveles sonoros, sino de garantizar la compatibilidad total entre actividad comercial intensiva y uso residencial de alta sensibilidad.

Se definieron soluciones adaptadas en cada tramo del sistema: control en origen, tratamientos de atenuación en conductos, desacoplamientos estructurales y medidas específicas de control vibratorio para evitar la transmisión a plantas superiores. El diseño se realizó contemplando además la adaptabilidad estructural y el comportamiento dinámico del conjunto.`,solutionEn:`The intervention required an integral analysis combining advanced acoustic modelling, specific sound propagation calculations and a detailed study of vibratory transmission through floor slabs and load-bearing structures. It was not merely about attenuating sound levels, but ensuring total compatibility between intensive commercial activity and highly sensitive residential use.

Tailored solutions were defined for each section of the system: source control, duct attenuation treatments, structural decoupling and specific vibration control measures to prevent transmission to upper floors. The design also considered structural adaptability and the dynamic behaviour of the assembly.`,result:"El resultado ha sido plenamente satisfactorio. Desde la puesta en marcha de la instalación, no se ha registrado ninguna molestia acústica ni vibratoria en las viviendas, consolidando la viabilidad de la actividad sin conflicto vecinal. Un ejemplo de intervención en entornos urbanos de alta complejidad donde ingeniería acústica avanzada, modelización rigurosa y soluciones innovadoras transforman configuraciones potencialmente conflictivas en sistemas plenamente compatibles.",resultEn:"The result has been fully satisfactory. Since the installation's commissioning, no acoustic or vibratory disturbance has been recorded in the dwellings, consolidating the viability of the activity without neighbourhood conflict. An example of intervention in highly complex urban environments where advanced acoustic engineering, rigorous modelling and innovative solutions transform potentially conflictive configurations into fully compatible systems.",images:[]},{slug:"campo-eolico-mantenimiento-predictivo",title:"Campo eólico: detección de problemas de mantenimiento mediante análisis de baja frecuencia",titleEn:"Wind farm: detecting maintenance issues through low-frequency analysis",tagline:"La firma acústica de baja frecuencia como herramienta predictiva de mantenimiento en aerogeneradores.",taglineEn:"Low-frequency acoustic signature as a predictive maintenance tool for wind turbines.",sector:"Medioambiental",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"Detección de anomalías mecánicas por firma acústica",keyFigureEn:"Mechanical anomaly detection via acoustic signature",technology:"Cámara acústica, análisis espectral de alta resolución",technologyEn:"Acoustic camera, high-resolution spectral analysis",challenge:`En instalaciones eólicas, la componente de baja frecuencia constituye uno de los parámetros más sensibles tanto desde el punto de vista ambiental como operativo. SNA desarrolló un estudio acústico avanzado en un campo eólico orientado a la detección temprana de posibles problemas de mantenimiento, poniendo especial énfasis en el análisis de baja frecuencia y componentes tonales asociadas al funcionamiento mecánico.

Estas componentes, aunque a veces poco perceptibles en términos globales, pueden generar penalizaciones normativas o convertirse en indicadores tempranos de anomalías técnicas como desalineaciones, desgaste en rodamientos, irregularidades en multiplicadoras o fenómenos aerodinámicos no previstos.`,challengeEn:`In wind installations, the low-frequency component is one of the most sensitive parameters from both an environmental and operational standpoint. SNA developed an advanced acoustic study at a wind farm aimed at early detection of potential maintenance issues, with special emphasis on low-frequency analysis and tonal components associated with mechanical operation.

These components, though sometimes barely perceptible in global terms, can trigger regulatory penalties or become early indicators of technical anomalies such as misalignments, bearing wear, gearbox irregularities or unforeseen aerodynamic phenomena.`,solution:`Mediante campañas de medición específicas y análisis espectral de alta resolución, se evaluó el comportamiento acústico de los aerogeneradores en bandas de frecuencia bajas. El estudio permitió diferenciar el patrón acústico normal de operación respecto a desviaciones significativas en baja frecuencia, correlacionando determinados eventos con estados concretos de carga y régimen de funcionamiento.

Este enfoque transformó el análisis acústico en una herramienta predictiva, anticipando intervenciones de mantenimiento antes de que los problemas evolucionaran hacia incidencias mayores o incumplimientos regulatorios.`,solutionEn:`Through specific measurement campaigns and high-resolution spectral analysis, the acoustic behaviour of wind turbines in low-frequency bands was evaluated. The study differentiated the normal acoustic operating pattern from significant low-frequency deviations, correlating certain events with specific load states and operating regimes.

This approach transformed acoustic analysis into a predictive tool, anticipating maintenance interventions before problems evolved into major incidents or regulatory non-compliance.`,result:"Además de su valor técnico-operativo, el control de baja frecuencia resulta determinante para garantizar la compatibilidad del parque con el entorno, especialmente en zonas próximas a núcleos habitados, donde este tipo de componente puede generar mayor sensibilidad social. El análisis de baja frecuencia se abordó no únicamente como requisito ambiental, sino como una herramienta estratégica para optimizar fiabilidad, reducir riesgos y mejorar el comportamiento global de la instalación.",resultEn:"Beyond its technical-operational value, low-frequency control is decisive for ensuring the wind farm's compatibility with its surroundings, especially in areas near inhabited settlements, where this type of component can generate greater social sensitivity. Low-frequency analysis was approached not merely as an environmental requirement but as a strategic tool to optimise reliability, reduce risks and improve the overall performance of the installation.",images:[]},{slug:"mapa-acustico-3d-planta-industrial",title:"Mapa acústico 3D medido in situ en planta industrial",titleEn:"3D acoustic map measured in situ at an industrial plant",tagline:"Cartografía tridimensional real de más de 6.000 m² para priorizar medidas de Prevención de Riesgos Laborales.",taglineEn:"Real three-dimensional cartography of over 6,000 m² to prioritise Occupational Risk Prevention measures.",sector:"Industrial",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"> 6.000 m² de superficie mapeada en 3D",keyFigureEn:"> 6,000 m² mapped in 3D",technology:"Medición espacial 3D de última generación",technologyEn:"State-of-the-art 3D spatial measurement",challenge:`En una planta industrial de alta complejidad, con más de 6.000 m² de superficie productiva y múltiples procesos simultáneos, identificar con precisión dónde nace el problema acústico y cómo se propaga dentro del recinto es clave para actuar con eficacia.

A diferencia de los enfoques basados en modelización o estimaciones, la necesidad era obtener datos reales medidos que permitieran reconstruir el comportamiento del ruido en el volumen del espacio, identificando zonas de acumulación, direcciones preferentes de propagación y áreas de exposición elevada con una precisión muy superior a la de campañas convencionales puntuales.`,challengeEn:`In a highly complex industrial plant, with over 6,000 m² of production area and multiple simultaneous processes, precisely identifying where the acoustic problem originates and how it propagates within the enclosure is key to effective action.

Unlike approaches based on modelling or estimates, the need was for real measured data that would allow reconstruction of noise behaviour across the volume of the space, identifying accumulation zones, preferential propagation directions and high-exposure areas with far greater precision than conventional point-based campaigns.`,solution:`SNA aplicó tecnología de última generación para realizar una medición real en tres dimensiones del campo acústico interior, obteniendo una cartografía 3D de la propagación del ruido.

El valor diferencial del sistema es que no solo ofrece niveles globales, sino también información espacial y espectral, permitiendo localizar y cuantificar con exactitud los focos dominantes y las frecuencias que más impactan en el entorno inmediato. Este aspecto resulta especialmente relevante en Prevención de Riesgos Laborales, ya que la exposición no depende únicamente del nivel total, sino del contenido frecuencial, la persistencia y la distribución real del ruido en los puestos de trabajo.`,solutionEn:`SNA applied state-of-the-art technology to perform a real three-dimensional measurement of the interior acoustic field, obtaining a 3D cartography of noise propagation.

The system's differential value is that it provides not only overall levels but also spatial and spectral information, enabling exact location and quantification of dominant sources and the frequencies that most impact the immediate environment. This is especially relevant for Occupational Risk Prevention, as exposure depends not only on the total level but on the frequency content, persistence and actual distribution of noise at workstations.`,result:'El resultado fue una herramienta de diagnóstico objetiva y altamente visual: un "mapa acústico 3D medido" que permite priorizar medidas correctoras con criterio técnico, optimizar inversiones y diseñar actuaciones de PRL más eficaces (zonificación, control en origen, apantallamientos, encapsulados, protocolos de exposición y selección de EPI), basadas en datos reales y no en hipótesis. Una evolución hacia una acústica industrial basada en medición avanzada, donde la tecnología aporta precisión, rapidez de decisión y máximo valor preventivo.',resultEn:'The result was an objective, highly visual diagnostic tool: a "measured 3D acoustic map" that enables prioritising corrective measures with technical criteria, optimising investments and designing more effective ORP actions (zoning, source control, screening, encapsulation, exposure protocols and PPE selection), based on real data rather than hypotheses. An evolution towards industrial acoustics based on advanced measurement, where technology provides precision, decision speed and maximum preventive value.',images:[]},{slug:"medicion-ruido-larga-distancia",title:"Medición de ruido a larga distancia: evaluación a más de 2 kilómetros",titleEn:"Long-distance noise measurement: assessment at over 2 kilometres",tagline:"Identificación de la firma acústica industrial discriminada del entorno a más de 2 km de distancia.",taglineEn:"Identification of the industrial acoustic signature, discriminated from the environment, at over 2 km distance.",sector:"Medioambiental",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"Medición a > 2 km del foco emisor",keyFigureEn:"Measurement at > 2 km from the emission source",technology:"Medición sincronizada origen-receptor, análisis de firma acústica",technologyEn:"Synchronised source-receptor measurement, acoustic signature analysis",challenge:`En entornos industriales de gran potencia, la afección acústica no siempre se limita al entorno inmediato de la instalación. SNA desarrolló una campaña de medición específica para evaluar la propagación del ruido a larga distancia, analizando su impacto en receptores situados a más de dos kilómetros del foco emisor.

La complejidad técnica radicaba en discriminar la contribución real de la instalación frente al ruido de fondo ambiental, considerando factores determinantes como condiciones meteorológicas, estabilidad atmosférica nocturna, posibles inversiones térmicas y el comportamiento de la baja frecuencia, capaz de mantener niveles apreciables a grandes distancias.`,challengeEn:`In high-power industrial environments, acoustic impact is not always limited to the installation's immediate surroundings. SNA developed a specific measurement campaign to evaluate long-distance noise propagation, analysing its impact on receptors located more than two kilometres from the emission source.

The technical complexity lay in discriminating the installation's real contribution from background environmental noise, considering determining factors such as meteorological conditions, nocturnal atmospheric stability, possible thermal inversions and the behaviour of low frequency, capable of maintaining appreciable levels over great distances.`,solution:'Se diseñó una estrategia de medición sincronizada en origen y en receptor, permitiendo correlacionar eventos operativos concretos con incrementos medidos en puntos alejados. El análisis espectral detallado facilitó la identificación de la "firma acústica" característica de la instalación, diferenciándola del entorno sonoro natural y de otras posibles fuentes.',solutionEn:`A synchronised measurement strategy at source and receptor was designed, enabling correlation of specific operational events with measured increases at distant points. Detailed spectral analysis facilitated the identification of the installation's characteristic "acoustic signature", differentiating it from the natural sound environment and other possible sources.`,result:"Los resultados permitieron cuantificar con rigor técnico la contribución real de la planta en receptores remotos, aportando una base objetiva para la toma de decisiones técnicas, correctoras y administrativas. Un estudio de propagación acústica compleja donde la distancia, la meteorología y la baja frecuencia requieren metodología avanzada, precisión en la medición y análisis experto.",resultEn:"The results enabled rigorous technical quantification of the plant's real contribution at remote receptors, providing an objective basis for technical, corrective and administrative decision-making. A complex acoustic propagation study where distance, meteorology and low frequency require advanced methodology, measurement precision and expert analysis.",images:[]},{slug:"data-center-centro-madrid",title:"Data Center en el centro de Madrid: grupos electrógenos de emergencia",titleEn:"Data Centre in central Madrid: emergency generator sets",tagline:"De más de 120 dB en origen a cumplimiento normativo con viviendas a menos de 20 metros.",taglineEn:"From over 120 dB at source to regulatory compliance with dwellings less than 20 metres away.",sector:"Industrial",solutionType:"Aislamiento acústico",location:"Madrid, España",locationEn:"Madrid, Spain",keyFigure:"> 120 dB en origen, viviendas a < 20 m",keyFigureEn:"> 120 dB at source, dwellings < 20 m away",regulation:"Normativa municipal de Madrid",regulationEn:"Madrid municipal regulations",challenge:`En el centro de Madrid, SNA desarrolló el proyecto y la posterior ejecución de medidas correctoras para el control acústico de tres grupos electrógenos de emergencia de gran capacidad instalados en cubierta en un edificio destinado a Data Center.

La complejidad del proyecto era especialmente elevada: los niveles sonoros en origen superaban los 120 dB, mientras que las viviendas más próximas se encontraban a menos de 20 metros de distancia. Este escenario exigía una intervención de máxima precisión técnica para garantizar la compatibilidad entre una infraestructura tecnológica crítica y un entorno residencial consolidado.`,challengeEn:`In central Madrid, SNA developed the project and subsequent execution of corrective measures for the acoustic control of three large-capacity emergency generator sets installed on the rooftop of a Data Centre building.

The project complexity was particularly high: source sound levels exceeded 120 dB, while the nearest dwellings were less than 20 metres away. This scenario required an intervention of maximum technical precision to ensure compatibility between critical technological infrastructure and a consolidated residential environment.`,solution:`El trabajo comenzó en fase de proyecto, donde se analizaron en detalle las emisiones en carga, la directividad, el comportamiento en baja frecuencia y la posible transmisión estructural. A partir de este diagnóstico se definió una estrategia integral que combinó encapsulados acústicos de alto aislamiento, tratamientos absorbentes interiores, diseño específico de silenciadores y control de vibraciones mediante sistemas de desacoplamiento adecuados a la masa y régimen de funcionamiento de los equipos.

Posteriormente, SNA participó en la fase de ejecución, supervisando la correcta implantación de las soluciones proyectadas, garantizando la estanqueidad acústica, la continuidad de los tratamientos y el control de posibles puentes rígidos o fugas sonoras.`,solutionEn:`Work began at the design stage, where emissions under load, directivity, low-frequency behaviour and possible structural transmission were analysed in detail. Based on this diagnosis, a comprehensive strategy was defined combining high-insulation acoustic enclosures, interior absorbent treatments, specific silencer design and vibration control through decoupling systems suited to the mass and operating regime of the equipment.

Subsequently, SNA participated in the execution phase, supervising the correct implementation of the designed solutions, ensuring acoustic tightness, treatment continuity and control of possible rigid bridges or sound leaks.`,result:"El resultado fue la reducción efectiva de la inmisión en fachada y el cumplimiento de la normativa municipal, asegurando la operatividad de los grupos electrógenos sin afección a las viviendas colindantes. Un proyecto de intervención en infraestructuras críticas en entornos urbanos de alta densidad, donde la ingeniería acústica combina diseño predictivo, ejecución rigurosa y soluciones innovadoras para compatibilizar continuidad operativa y protección del entorno residencial.",resultEn:"The result was an effective reduction of façade immission and compliance with municipal regulations, ensuring generator set operability without impacting adjacent dwellings. A critical infrastructure intervention project in high-density urban environments, where acoustic engineering combines predictive design, rigorous execution and innovative solutions to reconcile operational continuity and residential environment protection.",images:[]},{slug:"analisis-3d-ruido-carretera-zona-residencial",title:"Análisis 3D in situ de la propagación del ruido de carretera en zona residencial",titleEn:"In situ 3D analysis of road noise propagation in a residential area",tagline:"Análisis tridimensional real que demostró que la baja frecuencia es el factor determinante de afección en viviendas.",taglineEn:"Real three-dimensional analysis proving that low frequency is the determining factor of impact on dwellings.",sector:"Medioambiental",solutionType:"Monitorización y diagnóstico",location:"España",locationEn:"Spain",keyFigure:"Análisis 3D in situ con tecnología de medición espacial",keyFigureEn:"In situ 3D analysis with spatial measurement technology",technology:"Medición tridimensional multifrecuencial",technologyEn:"Multi-frequency three-dimensional measurement",challenge:`SNA Consultoría Acústica desarrolló un estudio de análisis tridimensional in situ para evaluar la propagación del ruido generado por una carretera y su afección directa en zonas residenciales próximas.

El objetivo no era únicamente determinar niveles globales, sino comprender cómo se comportan las distintas bandas de frecuencia durante su propagación hacia las viviendas: qué componentes se atenúan naturalmente y cuáles mantienen su capacidad de afección a distancia.`,challengeEn:`SNA Acoustic Consultancy developed an in situ three-dimensional analysis study to evaluate the propagation of noise generated by a road and its direct impact on nearby residential areas.

The objective was not merely to determine overall levels, but to understand how different frequency bands behave during propagation towards dwellings: which components attenuate naturally and which maintain their capacity for impact at distance.`,solution:`Mediante tecnología 3D de medición espacial avanzada, se analizó el comportamiento real del campo acústico en el entorno urbano, evaluando la distribución del ruido en diferentes puntos, alturas y fachadas.

El análisis permitió observar el fenómeno de atenuación natural de las frecuencias medias y altas debido a la distancia, la absorción atmosférica y la interacción con edificaciones. Sin embargo, el estudio confirmó que las componentes de baja frecuencia mantienen una capacidad de propagación significativamente mayor, alcanzando las viviendas residenciales con una atenuación mucho menor que el resto del espectro.`,solutionEn:`Using advanced 3D spatial measurement technology, the real behaviour of the acoustic field in the urban environment was analysed, evaluating noise distribution at different points, heights and façades.

The analysis revealed the natural attenuation phenomenon of mid and high frequencies due to distance, atmospheric absorption and interaction with buildings. However, the study confirmed that low-frequency components maintain significantly greater propagation capacity, reaching residential dwellings with much less attenuation than the rest of the spectrum.`,result:"La conclusión técnica fue clara: en todos los escenarios analizados, la baja frecuencia constituye el factor determinante de la afección acústica en las viviendas, mientras que las frecuencias medias y altas quedan parcialmente amortiguadas durante la propagación. Este tipo de análisis tridimensional real permite transformar la percepción subjetiva de molestia en un diagnóstico técnico objetivo, aportando una base sólida para la definición de medidas correctoras eficaces y adaptadas al comportamiento físico real del ruido de tráfico.",resultEn:"The technical conclusion was clear: in all scenarios analysed, low frequency constitutes the determining factor of acoustic impact on dwellings, while mid and high frequencies are partially damped during propagation. This type of real three-dimensional analysis transforms the subjective perception of annoyance into an objective technical diagnosis, providing a solid basis for defining effective corrective measures adapted to the actual physical behaviour of traffic noise.",images:[]}],s={"/":"/en","/metodologia":"/en/methodology","/metodologia/diagnostico":"/en/methodology/diagnosis","/metodologia/diseno":"/en/methodology/design","/metodologia/ejecucion":"/en/methodology/execution","/proyectos":"/en/projects","/proyectos/acustica-industrial":"/en/projects/industrial-acoustics","/proyectos/acustica-arquitectonica":"/en/projects/architectural-acoustics","/proyectos/acustica-medioambiental":"/en/projects/environmental-acoustics","/basslock":"/en/basslock","/basslock-distribuidores":"/en/basslock-distributors","/basslock-solicitud-enviada":"/en/basslock-application-sent","/sobre-nosotros":"/en/about","/contacto":"/en/contact","/aviso-legal":"/en/legal-notice","/politica-de-privacidad":"/en/privacy-policy","/politica-de-cookies":"/en/cookie-policy"},c=[["/proyectos/","/en/projects/"]];function l(e){return e.length>1&&e.endsWith("/")?e.slice(0,-1):e}function m(e,a){if(a==="es")return e;const i=l(e);if(s[i])return s[i];for(const[n,o]of c)if(i.startsWith(n))return o+i.slice(n.length);return`/en${i}`}function f(e){const a=l(e);if(a.startsWith("/en")){const n=Object.fromEntries(Object.entries(s).map(([o,t])=>[t,o]));if(n[a])return n[a];for(const[o,t]of c)if(a.startsWith(t))return o+a.slice(t.length);return a.replace(/^\/en/,"")||"/"}return m(a,"en")}export{m as a,g,p as l,h as p,f as s};
